		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>ספר הנביא ישעיהו פרק א כתוב:</p><p>כא אֵיכָה הָיְתָה לְזוֹנָה קִרְיָה נֶאֱמָנָה מְלֵאֲתִי מִשְׁפָּט צֶדֶק יָלִין בָּהּ וְעַתָּה מְרַצְּחִים.</p><p>כב כַּסְפֵּךְ הָיָה לְסִיגִים סָבְאֵךְ מָהוּל בַּמָּיִם.</p><p>כג שָׂרַיִךְ סוֹרְרִים וְחַבְרֵי גַּנָּבִים כֻּלּוֹ אֹהֵב שֹׁחַד וְרֹדֵף שַׁלְמֹנִים יָתוֹם לֹא יִשְׁפֹּטוּ וְרִיב אַלְמָנָה לֹא-יָבוֹא אֲלֵיהֶם.</p><p>כד לָכֵן נְאֻם הָאָדוֹן יְהוָה צְבָאוֹת אֲבִיר יִשְׂרָאֵל הוֹי אֶנָּחֵם מִצָּרַי וְאִנָּקְמָה מֵאוֹיְבָי.</p><p>כה וְאָשִׁיבָה יָדִי עָלַיִךְ וְאֶצְרֹף כַּבֹּר סִיגָיִךְ וְאָסִירָה כָּל-בְּדִילָיִךְ.</p><p>כו וְאָשִׁיבָה שֹׁפְטַיִךְ כְּבָרִאשֹׁנָה וְיֹעֲצַיִךְ כְּבַתְּחִלָּה אַחֲרֵי-כֵן יִקָּרֵא לָךְ עִיר הַצֶּדֶק קִרְיָה נֶאֱמָנָה.</p><p>כז צִיּוֹן בְּמִשְׁפָּט תִּפָּדֶה וְשָׁבֶיהָ בִּצְדָקָה.</p><p>כח וְשֶׁבֶר פֹּשְׁעִים וְחַטָּאִים יַחְדָּו וְעֹזְבֵי יְהוָה יִכְלוּ.</p><p>-</p><p>עמוס ט10: &quot;בַּחֶרֶב יָמוּתוּ כֹּל חַטָּאֵי עַמִּי הָאֹמְרִים לֹא תַגִּישׁ וְתַקְדִּים בַּעֲדֵינוּ הָרָעָה&quot;</p><p>מיכה ד8: &quot;וְאַתָּה מִגְדַּל עֵדֶר עֹפֶל בַּת צִיּוֹן עָדֶיךָ תֵּאתֶה וּבָאָה הַמֶּמְשָׁלָה הָרִאשֹׁנָה מַמְלֶכֶת לְבַת יְרוּשָׁלָים&quot;</p><p>-</p><p>עתה באור לפרש לכם</p><p>כא אֵיכָה הָיְתָה לְזוֹנָה קִרְיָה נֶאֱמָנָה מְלֵאֲתִי מִשְׁפָּט צֶדֶק יָלִין בָּהּ וְעַתָּה מְרַצְּחִים. --- זאת הממשלה האחרונה ממשלת ימין שקר</p><p>תהלים קמד8: &quot;אֲשֶׁר פִּיהֶם דִּבֶּר שָׁוְא וִימִינָם יְמִין שָׁקֶר&quot; אלה הם אנשי הממשלה האחרונה ממשלת ימין שקר וכל תומכיהם הרשעים כולל כל הרבנים אשר חרפו את יהוה ומשיחו</p><p>כד לָכֵן נְאֻם הָאָדוֹן יְהוָה צְבָאוֹת אֲבִיר יִשְׂרָאֵל הוֹי אֶנָּחֵם מִצָּרַי וְאִנָּקְמָה מֵאוֹיְבָי. --- לאמור כי תהיה נקמה באויבי יהוה</p><p>ואחרי כן --- וּבָאָה הַמֶּמְשָׁלָה הָרִאשֹׁנָה מַמְלֶכֶת לְבַת יְרוּשָׁלָים</p><p>--------------------------------------------------------------------</p><p>קראו נא בספר תהילות פרק ב ככתוב:</p><p>א לָמָּה רָגְשׁוּ גוֹיִם וּלְאֻמִּים יֶהְגּוּ-רִיק.</p><p>ב יִתְיַצְּבוּ מַלְכֵי-אֶרֶץ וְרוֹזְנִים נוֹסְדוּ-יָחַד עַל-יְהוָה וְעַל-מְשִׁיחוֹ.</p><p>ג נְנַתְּקָה אֶת-מוֹסְרוֹתֵימוֹ וְנַשְׁלִיכָה מִמֶּנּוּ עֲבֹתֵימוֹ.</p><p>ד יוֹשֵׁב בַּשָּׁמַיִם יִשְׂחָק אֲדֹנָי יִלְעַג-לָמוֹ.</p><p>ה אָז יְדַבֵּר אֵלֵימוֹ בְאַפּוֹ וּבַחֲרוֹנוֹ יְבַהֲלֵמוֹ.</p><p>ו וַאֲנִי נָסַכְתִּי מַלְכִּי עַל-צִיּוֹן הַר-קָדְשִׁי.</p><p>ז אֲסַפְּרָה אֶל-חֹק יְהוָה אָמַר אֵלַי בְּנִי אַתָּה אֲנִי הַיּוֹם יְלִדְתִּיךָ.</p><p>ח שְׁאַל מִמֶּנִּי וְאֶתְּנָה גוֹיִם נַחֲלָתֶךָ וַאֲחֻזָּתְךָ אַפְסֵי-אָרֶץ.</p><p>ט תְּרֹעֵם בְּשֵׁבֶט בַּרְזֶל כִּכְלִי יוֹצֵר תְּנַפְּצֵם.</p><p>י וְעַתָּה מְלָכִים הַשְׂכִּילוּ הִוָּסְרוּ שֹׁפְטֵי אָרֶץ.</p><p>יא עִבְדוּ אֶת-יְהוָה בְּיִרְאָה וְגִילוּ בִּרְעָדָה.</p><p>יב נַשְּׁקוּ-בַר פֶּן-יֶאֱנַף וְתֹאבְדוּ דֶרֶךְ כִּי-יִבְעַר כִּמְעַט אַפּוֹאַשְׁרֵי כָּל-חוֹסֵי בוֹ.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-02-22 06:33:34'
		)
