		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_6.html',
		'<p>בסוף פברואר תחילת מרס 2026 החלה פריחת השעורה אביב בלב הארץ במרכז ובדרום</p><p>אבל בצפון בתחילת אפריל עד סוף החודש פריחת השעורה אביב לאמור כי כחודשיים ימים</p><p>מתחילת מרס עד סוף אפריל והאביב על פי התורה הוא רק חודש ימים ולא חודשיים</p><p>לאמור לכם כי אף על פי שבתחילת מרס החלה פריחת האביב בירחא ניסן [פורים שלכם]</p><p>אין זה חודש האביב הרשמי כי אם יום שיוויון האביב הוא ראש החודש האביב הרשמי </p><p>כי הוא בדיוק בתווך בין פריחת האביב שבדרום לבין פריחת האביב שבצפון</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-03 06:27:07'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_6.html',
		'<p>בסוף פברואר תחילת מרס 2026 החלה פריחת השעורה אביב בלב הארץ במרכז ובדרום</p><p>אבל בצפון בתחילת אפריל עד סוף החודש פריחת השעורה אביב לאמור כי כחודשיים ימים</p><p>מתחילת מרס עד סוף אפריל והאביב על פי התורה הוא רק חודש ימים ולא חודשיים</p><p>לאמור לכם כי אף על פי שבתחילת מרס החלה פריחת האביב בירחא ניסן [פורים שלכם]</p><p>אין זה חודש האביב הרשמי כי אם יום שיוויון האביב הוא ראש החודש האביב הרשמי</p><p>כי הוא בדיוק בתווך בין פריחת האביב שבדרום לבין פריחת האביב שבצפון</p><p>https://drive.google.com/file/d/1V0L3yHOiec7YqxDnt-a_34-nDoRSygMz/view?usp=drivesdk</p>',
		'115934331744503251746',
		'DAIAN SHEM',
