		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p>לוח השנה בן 364 ימים כאשר בפועל השנה בת 365.14 ימים</p><p>אם למשל ראש חודש האביב בלוח השמש היה יום ראשון</p><p>ושנה הבאה ראש חודש האביב בלוח השמש יהיה גם יום ראשון</p><p>אבל יום השיויון הוא ביום שני</p><p>ובשנה הבאה [כמובן שנת 364 ימים] ראש חודש האביב גם ביום ראשון</p><p>אבל יום השיויון עבר ליום שלישי --- כי השנה בפועל היא 365.14 ימים</p><p>ובשנה הבאה ראש חודש האביב גם ביום ראשון אך יום השיויון ביום רביעי</p><p>ובשנה הבאה ראש חודש האביב גם ביום ראשון אך יום השיויון ביום חמישי</p><p>ובשנה הבאה ראש חודש האביב גם ביום ראשון אך יום השיויון ביום שישי</p><p>ובשנה הבאה ראש חודש האביב גם ביום ראשון אך יום השיויון ביום שבת</p><p>וכשייש נסיגה של שבוע ימים מעברים את השנה בשמונת ימי מילואים כך שראש חודש האביב עובר מיום ראשון ליום שני</p><p>-</p><p>כי יש נסיגה של כשבוע ימים בין ראש חודש האביב בלוח השנה לבין יום השיויון האסטרונומי</p><p>וזה מה שקובע את תקופת האביב בראש השנה עם השלכות לכל מועד הפריחה והלבלוב של הצומח וכן למסיק הזיתים</p><p>יש מרחק של כשבעה חודשים בין ראש חודש האביב לבין מסיק הזיתים בחודש השמיני [מלשון שמנ=שמן]</p><p>אם ראש חודש האביב בלוח השנה שלי [שכתבתי] מועדו היה ביום שיויון האביב אז גם מסיק הזיתים יהיה בחודש השמיני [כחודש ימים לאחר יום שיויון הסתיו]</p><p>ואם ראש חודש האביב בלוח השנה שלי [שכתבתי] מועדו היה כשבוע ימים או מספר ימים לפני יום שיויון האביב האסטרונומי אז גם מועד מסיק הזיתים יהיה קודם בהתאם</p><p>---------------------------------------------</p><p>שנים עם אביב מוקדם → מסיק מוקדם</p><p>שנים עם אביב מאוחר → מסיק מאוחר</p><p>-</p><p>אמנם אין קשר ביולוגי ישיר בין פריחת השעורה לבין מסיק הזיתים</p><p>אך הקשר מתבטא בלוח השנה שכתבתי לכם.</p><p>וגם יש קשר אקלימי עקיף: שנה חמה → פריחה מוקדמת → מסיק מוקדם; שנה קרה → פריחה מאוחרת → מסיק מאוחר.</p><p>לכן אפשר להשתמש בפריחת האביב כ&quot;סמן&quot; כללי למועד המסיק</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-03 15:26:29'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

