		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2823_0.html',
		'<p>משלי טו30: &quot;מְאוֹר עֵינַיִם יְשַׂמַּח לֵב....... שְׁמוּעָה טוֹבָה תְּדַשֶּׁן עָצֶם&quot;</p><p>תהלים קד15: &quot;וְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ....... לְהַצְהִיל פָּנִים מִשָּׁמֶן וְלֶחֶם לְבַב אֱנוֹשׁ יִסְעָד&quot;</p><p>וְיַיִן יְשַׂמַּח לְבַב אֱנוֹשׁ = מְאוֹר עֵינַיִם יְשַׂמַּח לֵב </p><p> בראשית מט12: &quot;חַכְלִילִי עֵינַיִם מִיָּיִן .......וּלְבֶן שִׁנַּיִם מֵחָלָב&quot;</p><p>-</p><p>שימו לב כי היין אמנם מחזק את עיני-האדם --------- [=עיני בשר הגוף]</p><p>אבל אסור שזה יבוא על חשבון עיני-האלהים באדם - [=העיניים הרוחניות]</p><p>ולכן הנביא מזהיר את הכהנים והנביאים מלשגות ביין ובשכר</p><p>ישעיהו כח7: &quot;וְגַם אֵלֶּה בַּיַּיִן שָׁגוּ וּבַשֵּׁכָר תָּעוּ כֹּהֵן וְנָבִיא שָׁגוּ בַשֵּׁכָר נִבְלְעוּ מִן הַיַּיִן תָּעוּ מִן הַשֵּׁכָר שָׁגוּ בָּרֹאֶה פָּקוּ פְּלִילִיָּה&quot; </p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-07 16:57:23'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_6.html',
		'<p>יום שוויון האביב = הוא ראש חודש האביב הוא ראש השנה</p><p>אך שימו לב.......</p><p>מדובר על יום השיוויון בין היום והלילה ולא יום השיוויון האסטרונומי אשר חל שבוע ימים אחריו</p><p>ביום השיוויון האביבי בין היום והלילה אז יחל ראש-חדש-השעורה-אביב הוא ראש השנה</p><p>ככה מדדו בימי קדם את יום השיויון </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-08 05:38:04'
		)
		;

SET character_set_client=utf8mb3;
