		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>  המלחמה באחרית הימים מלחמה בין כהנים-מלאכים צדיקים לבין כהנים מלאכים רשעים </p><p>מדוע אני מדגיש לכם זאת למען תדעו כי המלאכים הרשעים גם הם כהנים כהני-דת רבנים</p><p>והם תֹפְשֵׂי הַתּוֹרָה אשר  לֹא יודעים את יהוה זה לא חכמה לתפוש בתורה ולדקלם מבלי לדעת את יהוה אלהים</p><p>ירמיהו ב8: &quot;הַכֹּהֲנִים לֹא אָמְרוּ אַיֵּה יהוה וְתֹפְשֵׂי הַתּוֹרָה לֹא יְדָעוּנִי וְהָרֹעִים פָּשְׁעוּ בִי וְהַנְּבִיאִים נִבְּאוּ בַבַּעַל וְאַחֲרֵי לֹא יוֹעִלוּ הָלָכוּ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-12 13:07:57'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>המלחמה באחרית הימים מלחמה בין כהנים-מלאכים צדיקים לבין כהנים מלאכים רשעים</p><p>מדוע אני מדגיש לכם זאת למען תדעו כי המלאכים הרשעים גם הם כהנים כהני-דת רבנים</p><p>גם הם יודעים את התורה אבל לבם רחוק מאלהים</p><p>נאמר על חלק נכבד מרבני הָעָם הַזֶּה</p><p>ישעיהו כט13: &quot;וַיֹּאמֶר אֲדֹנָי יַעַן כִּי נִגַּשׁ הָעָם הַזֶּה בְּפִיו וּבִשְׂפָתָיו כִּבְּדוּנִי וְלִבּוֹ רִחַק מִמֶּנִּי וַתְּהִי יִרְאָתָם אֹתִי מִצְוַת אֲנָשִׁים מְלֻמָּדָה&quot;</p><p>ישעיהו כט14: &quot;לָכֵן הִנְנִי יוֹסִף לְהַפְלִיא אֶת הָעָם הַזֶּה הַפְלֵא וָפֶלֶא וְאָבְדָה חָכְמַת חֲכָמָיו וּבִינַת נְבֹנָיו תִּסְתַּתָּר&quot;</p><p>תֹפְשֵׂי הַתּוֹרָה אשר לֹא יודעים את יהוה לא חכמה להם לתפוש בתורה ולדקלם מבלי לדעת את יהוה אלהים</p><p>ירמיהו ב8: &quot;הַכֹּהֲנִים לֹא אָמְרוּ אַיֵּה יהוה וְתֹפְשֵׂי הַתּוֹרָה לֹא יְדָעוּנִי וְהָרֹעִים פָּשְׁעוּ בִי וְהַנְּבִיאִים נִבְּאוּ בַבַּעַל וְאַחֲרֵי לֹא יוֹעִלוּ הָלָכוּ&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-13 01:43:31'
		)
		;

SET character_set_client=utf8mb3;
