		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2801_1.html',
		'<p>כשם שאדם אוכל יום יום למען התחדש משכנו-גופו באופן קבוע</p><p>כן עליו לעשות צדקה ומשפט יום יום למען התחדשות הרוחנית</p><p>ישעיהו נח2: &quot;וְאוֹתִי יוֹם יוֹם יִדְרֹשׁוּן וְדַעַת דְּרָכַי יֶחְפָּצוּן כְּגוֹי אֲשֶׁר צְדָקָה עָשָׂה וּמִשְׁפַּט אֱלֹהָיו לֹא עָזָב יִשְׁאָלוּנִי מִשְׁפְּטֵי צֶדֶק קִרְבַת אֱלֹהִים יֶחְפָּצוּן&quot;</p><p>כי בני-עם-יהוה בדרך האל הקדוש בעשות צדקה = ישעיהו ה16: &quot;וַיִּגְבַּה יהוה צְבָאוֹת בַּמִּשְׁפָּט וְהָאֵל הַקָּדוֹשׁ נִקְדָּשׁ בִּצְדָקָה&quot;</p><p>-</p><p>האכילה מחזירה את הגוף לחיים בכל יום.</p><p>הצדקה והמשפט מחזירים את הרוח לחיים בכל יום.</p><p>זו לא מטאפורה בלבד — זה מבנה רוחני:</p><p>הגוף מתכלה אם אינו אוכל.</p><p>הרוח מתקהה אם אינה עושה צדקה ומשפט.</p><p>הלב מתייבש אם אינו מתחדש.</p><p>הנוכחות הפנימית דועכת אם אינה מופעלת.</p><p>למה ההתחדשות חייבת להיות יומיומית</p><p>1) העולם משתנה כל יום</p><p>כל יום אתה פוגש מצבים חדשים, אנשים חדשים, אתגרים חדשים.</p><p>הצדקה של אתמול לא פותרת את מבחן היום.</p><p>2) האדם משתנה כל יום</p><p>היצר, הכעס, הפחד, האגו — כולם מתעוררים מחדש.</p><p>3) הנוכחות האלוהית אינה מצב קבוע</p><p>היא מתעוררת בכל פעם שאתה משווה את יהוה לנגד עיניך.</p><p>תהלים טז8: &quot;שִׁוִּיתִי יהוה לְנֶגְדִּי תָמִיד....... כִּי מִימִינִי בַּל אֶמּוֹט&quot;</p><p>תמיד = התחדשות, לא קביעות.</p><p>הבה נחדש ימינו כקדם....................................................................</p><p>גם מבחינה רוחנית=צדקה ומשפט --- וגם מבחינה גופנית=לאכול ולשתות</p><p>ירמיהו כב15: &quot;הֲתִמְלֹךְ כִּי אַתָּה מְתַחֲרֶה בָאָרֶז אָבִיךָ הֲלוֹא אָכַל וְשָׁתָה וְעָשָׂה מִשְׁפָּט וּצְדָקָה אָז טוֹב לוֹ&quot; </p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-17 06:06:47'
		)
		;

SET character_set_client=utf8mb3;
