		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0127_3.html',
		'<p>תהלים קטו13: &quot;יְבָרֵךְ יִרְאֵי יהוה הַקְּטַנִּים עִם הַגְּדֹלִים&quot;</p><p>הברכה מאת יהוה אינה תלויה בגודל המעשה אלא ביראת יהוה שמולידה אותו.</p><p>על כן דע כי כל מעשה קטן שלך ביראת אלהים מביא ברכה לך ולעולם</p><p>זה העולם חסד יבנה אשר יהוה חפץ בו דרך המעשים הקטנים והגדולים</p><p>וכן הבן שאת יראי יהוה הקטנים שם לפני יראי יהוה הגדולים</p><p>על כן שמח בני מכל מעשה קטן שאתה עושה ביראת-אלהים</p><p>ואל תאמר ההוא ירא-אלהים גדול ומי אנכי הירא-הקטן</p><p>כי יראת אלהים לא בהכרח לפי גודל המעשה אלא לפי אמת הלב</p><p>כי אין הבדל בלב של אמת בין אם קטן ובין אם גדול</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-17 10:11:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0127_3.html',
		'<p>תהלים קטו13: &quot;יְבָרֵךְ יִרְאֵי יהוה הַקְּטַנִּים עִם הַגְּדֹלִים&quot;</p><p>הברכה מאת יהוה אינה תלויה בגודל המעשה אלא ביראת יהוה שמולידה אותו.</p><p>על כן דע כי כל מעשה קטן שלך ביראת אלהים מביא ברכה לך ולעולם</p><p>זה העולם חסד יבנה אשר יהוה חפץ בו דרך המעשים הקטנים והגדולים</p><p>וכן הבן שאת יראי יהוה הקטנים שם לפני יראי יהוה הגדולים</p><p>על כן שמח בני מכל מעשה קטן שאתה עושה ביראת-אלהים</p><p>ואל תאמר ההוא ירא-אלהים גדול ומי אנכי הירא-הקטן</p><p>כי יראת אלהים לא בהכרח לפי גודל המעשה אלא לפי אמת הלב</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-17 10:12:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

