		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p>לוח השנה נראה כך:</p><p>364*6=2184</p><p>364+8=372 ימים בשנת שמיטה</p><p>ובכל 49 שנות היובל 17892 ימים</p><p>לאמור כי בכל שנת שבע יש קפיצה של יום אחד</p><p>אבל אם רוצים שהמועדים יהיו קבועים באותו יום</p><p>אז כל שנת שבע מעברים 7 ימים = 49 ימי עיבור</p><p>ובשנת היובל 7 ימים נוספים סה&quot;כ 56 ימי עיבור</p><p>364*49=17836</p><p>17836+56= 17892 ימים בכל מחזור היובל</p><p>לאמור לכם מספר הימים בשנה הוא 365 ושביעית יום או 365.14</p><p>365.14*49=17892 זה מספר הימים בארבעים ותשע שנות יובל בכל מקרה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-22 17:46:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0101_23.html',
		'<p>לוח השנה נראה כך:</p><p>364*6=2184</p><p>364+8=372 ימים בשנת שמיטה</p><p>ובכל 49 שנות היובל 17892 ימים</p><p>לאמור כי בכל שנת שבע יש קפיצה של יום אחד</p><p>אבל אם רוצים שהמועדים יהיו קבועים באותו יום</p><p>אז כל שנת שבע מעברים 7 ימים = 49 ימי עיבור</p><p>ובשנת היובל 7 ימים נוספים סה&quot;כ 56 ימי עיבור</p><p>364*49=17836</p><p>17836+56= 17892 ימים בכל מחזור היובל</p><p>לאמור לכם מספר הימים בשנה הוא 365 ושביעית יום או 365.14</p><p>365.14*49=17892 זה מספר הימים בארבעים ותשע שנות יובל בכל מקרה</p><p>ורמז לכך נמצא בפסוק הבא</p><p>מלכים א ח65: &quot;וַיַּעַשׂ שְׁלֹמֹה בָעֵת הַהִיא אֶת הֶחָג וְכָל יִשְׂרָאֵל עִמּוֹ קָהָל גָּדוֹל מִלְּבוֹא חֲמָת עַד נַחַל מִצְרַיִם לִפְנֵי יהוה אֱלֹהֵינוּ שִׁבְעַת יָמִים וְשִׁבְעַת יָמִים אַרְבָּעָה עָשָׂר יוֹם&quot; </p><p>364*49 =17836</p><p>6 שנים * 7 ימי עיבור = 42</p><p>+ ימי עיבור בשנת היובל 14</p><p>סה&quot;כ 56 ימי עיבור + 17836 ימים = 17892 בכל מחזור היובל</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-22 17:52:21'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
