		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0531_1.html',
		'<p>ספר צוואת לוי בן יעקב פרק יא כתוב:</p><p>א) ואקח לי אישה ואני בן שמונה ועשרים שנה ושמה מלכה.</p><p>ב) ותהר ותלד בן ואקרא שמו גרשם כי גרים היינו בארצנו.</p><p>ג) ואדע כי הוא לא יהיה במערכת הראשונה.</p><p>ד) ובשנת חמש ושלושים לחיי נולד קהת לעת עלות השמש.</p><p>ה) ואראה בחלומי והנה הוא עומד במעלה בתוך כל הקהל.</p><p>ו) על כן קראתי שמו קהת כי הוא ראשית התפארת והקהילה.</p><p>ז) ותלד לי בן שלישי את מררי בשנת ארבעים לחיי. ויהי בהקשות אמו בלדתה ואקרא שמו מררי לאמור מרתי כי גם הוא נטה למות........</p><p>איוב כח12: &quot;וְהַחָכְמָה מֵאַיִן תִּמָּצֵא וְאֵי זֶה מְקוֹם בִּינָה&quot;</p><p>איוב כח13: &quot;לֹא יָדַע אֱנוֹשׁ עֶרְכָּהּ וְלֹא תִמָּצֵא בְּאֶרֶץ הַחַיִּים&quot; ------- כי גם הוא נטה למות........</p><p>על כן שבט לוי הוא שבט החכמה ממנו כהני-יהוה</p><p>על כן גם זקני-ישראל נושאים ברוח הקודש את ארון הברית כי גם זקני-ישראל נוטים למות</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-03-25 14:54:03'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

