		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t3109_0.html',
		'<p>קהלת ז12: &quot;כִּי בְּצֵל הַחָכְמָה בְּצֵל הַכָּסֶף וְיִתְרוֹן דַּעַת הַחָכְמָה תְּחַיֶּה בְעָלֶיהָ&quot;</p><p>קהלת ז12: &quot;כִּי בְּצֵל הַחָכְמָה = בְּצֵל הַכָּסֶף</p><p>------------------------ חָכְמָה = כָּסֶף ----------------------- וְהַכֶּסֶף יַעֲנֶה אֶת הַכֹּל</p><p>וְיִתְרוֹן דַּעַת הַחָכְמָה תְּחַיֶּה בְעָלֶיהָ&quot;</p><p>תהלים קיח18: &quot;יַסֹּר יִסְּרַנִּי יָּהּ וְלַמָּוֶת לֹא נְתָנָנִי&quot;</p><p>הייתי קרוב למות אך דעת החכמה נתנה לי חיים</p><p>לא קיבלתי חינם את החכמה</p><p>אלהים נתן לי חכמה למען החיות את נפשי כי ראה בסבלי בעוניי</p><p>ועתה אני כותב לכם דברי חכמה להושיע נַפְשׁוֹת אֶבְיוֹנִים</p><p>תהלים עב13: &quot;יָחֹס עַל דַּל וְאֶבְיוֹן וְנַפְשׁוֹת אֶבְיוֹנִים יוֹשִׁיעַ&quot;</p><p>-------------------------------------------------------</p><p>בספר איוב פרק כח כתוב:</p><p>יב וְהַחָכְמָה מֵאַיִן תִּמָּצֵא וְאֵי זֶה מְקוֹם בִּינָה.</p><p>יג לֹא-יָדַע אֱנוֹשׁ עֶרְכָּהּ וְלֹא תִמָּצֵא בְּאֶרֶץ הַחַיִּים.</p><p>יד תְּהוֹם אָמַר לֹא בִי-הִיא וְיָם אָמַר אֵין עִמָּדִי.</p><p>טו לֹא-יֻתַּן סְגוֹר תַּחְתֶּיהָ וְלֹא יִשָּׁקֵל כֶּסֶף מְחִירָהּ</p><p>-</p><p>עתה שימו לב</p><p>קהלת מדבר על חכמת-אדם — ולכן משווה אותה לכסף.</p><p>איוב מדבר על חכמת-אלהים — ולכן היא יקרה מכל כסף.</p><p>-</p><p>חכמת בני-אדם = כסף בני אדם</p><p>חכמת אלהים = כסף אלהים ----אלה דברי-יהוה = אמרי-יה = אִמֲרוֹת יהוה</p><p> תהלים יב7: &quot;אִמֲרוֹת יהוה אִמֲרוֹת טְהֹרוֹת כֶּסֶף צָרוּף בַּעֲלִיל לָאָרֶץ מְזֻקָּק שִׁבְעָתָיִם&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-06 02:24:49'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

