		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2655_5.html',
		'<p>מים טהורים רגישים יותר לכל זוהמה</p><p>קשה יותר לשמור על מים טהורים מאשר על מים עכורים</p><p>ואני במלחמה מתמדת לשמור על טהרתי בסביבה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-06 06:35:14'
		)
		;

SET character_set_client=utf8mb3;
