		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/tora/jmot/jm-30-13.html',
		'<p>הנה עדכון לשקל הקודש</p><p>*** היום 6 לאפריל 2026 ***</p><p>מחיר 1 אונקיית כסף = 73 דולר* 3 שקלים[בערך שער הדולר] 73*3= בערך 220 ש&quot;ח</p><p>מחיר 5 אונקיות כסף = 1100 ש&quot;ח = רבע שקל כסף אשר יש לתת לנביא לדרוש אלהים</p><p>מחיר 10 אונקיות כסף = 2200 ש&quot;ח = מחצית השקל = זה כסף הכפורים אשר יש לתת ביום הכפורים למקדש לכפר על נפשותיכם</p><p>מחיר 20 אונקיות כסף = 4400 ש&quot;ח זה שוויו של 1 שקל הקודש</p><p>-------------------------------------------------------------------------</p><p>שמואל א ט8: &quot;וַיֹּסֶף הַנַּעַר לַעֲנוֹת אֶת שָׁאוּל וַיֹּאמֶר הִנֵּה נִמְצָא בְיָדִי רֶבַע שֶׁקֶל כָּסֶף וְנָתַתִּי לְאִישׁ הָאֱלֹהִים וְהִגִּיד לָנוּ אֶת דַּרְכֵּנוּ&quot;</p><p>ברגע שדיברו על רבע שקל כסף במקרא -- זה נקבע לדורות התשורה שצריך לתת לנביא באופן מכבד </p><p>זה בערך מה שנותנים למתקשר-רוחני אשר הוא &quot;רואה&quot; במובן של דורנו</p><p>מחיר 5 אונקיות כסף  = רבע שקל כסף אשר יש לתת לנביא לדרוש אלהים</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-06 09:35:39'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/tora/jmot/jm-30-13.html',
		'<p>הנה עדכון לשקל הקודש</p><p>*** היום 6 לאפריל 2026 ***</p><p>מחיר 1 אונקיית כסף = 73 דולר* 3 שקלים[בערך שער הדולר] 73*3= בערך 220 ש&quot;ח</p><p>מחיר 5 אונקיות כסף = 1100 ש&quot;ח = רבע שקל כסף אשר יש לתת לנביא לדרוש אלהים</p><p>מחיר 10 אונקיות כסף = 2200 ש&quot;ח = מחצית השקל = זה כסף הכפורים אשר יש לתת ביום הכפורים למקדש לכפר על נפשותיכם</p><p>מחיר 20 אונקיות כסף = 4400 ש&quot;ח זה שוויו של 1 שקל הקודש</p><p>-------------------------------------------------------------------------</p><p>שמואל א ט8: &quot;וַיֹּסֶף הַנַּעַר לַעֲנוֹת אֶת שָׁאוּל וַיֹּאמֶר הִנֵּה נִמְצָא בְיָדִי רֶבַע שֶׁקֶל כָּסֶף וְנָתַתִּי לְאִישׁ הָאֱלֹהִים וְהִגִּיד לָנוּ אֶת דַּרְכֵּנוּ&quot;</p><p>ברגע שדיברו על רבע שקל כסף במקרא -- זה נקבע לדורות התשורה שצריך לתת לנביא באופן מכבד</p><p>זה בערך מה שנותנים למתקשר-רוחני אשר הוא &quot;רואה&quot; במובן של דורנו</p><p>מחיר 5 אונקיות כסף = רבע שקל כסף אשר יש לתת לנביא לדרוש אלהים</p><p>---------------------------------------------------------------------------------------------------------------------------</p><p>מחיר “מחצית השקל” לפי ערך הרבנים כיום [2026] נע בסביבות 30 ש&quot;ח בהתאם לשיטה ההלכתית ולשער הכסף. </p><p>לאמור כי &quot;רבע שקל כסף לפי הרבנים כיום [2026] נע בסביבות 15 ש&quot;ח וזה מה שהרבנים רוצים לתת לנביא כדי שיקנה מסטיק בזוקה חחחח ברור כי זה לא מכובד</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-06 10:06:09'
		)
		;

