		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0324_0.html',
		'<p>תהלים קיט109: &quot;נַפְשִׁי בְכַפִּי תָמִיד וְתוֹרָתְךָ לֹא שָׁכָחְתִּי&quot;</p><p>&quot;נַפְשִׁי בְכַפִּי תָמִיד = זה זכרון-יהוה על כן וְתוֹרָתְךָ לֹא שָׁכָחְתִּי&quot;</p><p>נַפְשִׁי בְכַפִּי תָמִיד = זה זכרון-יהוה</p><p>תהלים כג4: &quot;גַּם כִּי אֵלֵךְ בְּגֵיא צַלְמָוֶת לֹא אִירָא רָע כִּי אַתָּה עִמָּדִי שִׁבְטְךָ וּמִשְׁעַנְתֶּךָ הֵמָּה יְנַחֲמֻנִי&quot;</p><p>נפשי בכפי תמיד --- תרתי משמע</p><p>וזכרון-יהוה מתבטא במיוחד כאשר</p><p>הנפש מאלהיך על כף ידך</p><p>תהלים קכא5: &quot;יהוה שֹׁמְרֶךָ יהוה צִלְּךָ עַל יַד יְמִינֶךָ&quot;</p><p>-</p><p>דוגמאות לנפשי בכפי כאשר אדם שם נפשו בכפו נכנס לאש הסכנה אך מקווה לטוב ובוטח באלהים כי נדרש למען מטרה נשגבה</p><p>שופטים יב3: &quot;וָאֶרְאֶה כִּי אֵינְךָ מוֹשִׁיעַ וָאָשִׂימָה נַפְשִׁי בְכַפִּי....... וָאֶעְבְּרָה אֶל בְּנֵי עַמּוֹן וַיִּתְּנֵם יהוה בְּיָדִי וְלָמָה עֲלִיתֶם אֵלַי הַיּוֹם הַזֶּה לְהִלָּחֶם בִּי&quot;</p><p>שמואל א כח21: &quot;וַתָּבוֹא הָאִשָּׁה אֶל שָׁאוּל וַתֵּרֶא כִּי נִבְהַל מְאֹד וַתֹּאמֶר אֵלָיו הִנֵּה שָׁמְעָה שִׁפְחָתְךָ בְּקוֹלֶךָ וָאָשִׂים נַפְשִׁי בְּכַפִּי....... וָאֶשְׁמַע אֶת דְּבָרֶיךָ אֲשֶׁר דִּבַּרְתָּ אֵלָי&quot;</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 10:11:53'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0324_0.html',
		'<p>האדם הוא נפש חיה אז איך מגיעים לזה שנפשך המקורית תמיד תהיה איתך</p><p>תהלים קיט109: &quot;נַפְשִׁי בְכַפִּי תָמִיד וְתוֹרָתְךָ לֹא שָׁכָחְתִּי&quot;</p><p>&quot;נַפְשִׁי בְכַפִּי תָמִיד = זה זכרון-יהוה על כן וְתוֹרָתְךָ לֹא שָׁכָחְתִּי&quot;</p><p>נַפְשִׁי בְכַפִּי תָמִיד = זה זכרון-יהוה</p><p>תהלים כג4: &quot;גַּם כִּי אֵלֵךְ בְּגֵיא צַלְמָוֶת לֹא אִירָא רָע כִּי אַתָּה עִמָּדִי שִׁבְטְךָ וּמִשְׁעַנְתֶּךָ הֵמָּה יְנַחֲמֻנִי&quot;</p><p>נפשי בכפי תמיד --- תרתי משמע</p><p>וזכרון-יהוה מתבטא במיוחד כאשר</p><p>הנפש מאלהיך על כף ידך</p><p>תהלים קכא5: &quot;יהוה שֹׁמְרֶךָ יהוה צִלְּךָ עַל יַד יְמִינֶךָ&quot;</p><p>-</p><p>דוגמאות לנפשי בכפי כאשר אדם שם נפשו בכפו נכנס לאש הסכנה אך מקווה לטוב ובוטח באלהים כי נדרש למען מטרה נשגבה</p><p>שופטים יב3: &quot;וָאֶרְאֶה כִּי אֵינְךָ מוֹשִׁיעַ וָאָשִׂימָה נַפְשִׁי בְכַפִּי....... וָאֶעְבְּרָה אֶל בְּנֵי עַמּוֹן וַיִּתְּנֵם יהוה בְּיָדִי וְלָמָה עֲלִיתֶם אֵלַי הַיּוֹם הַזֶּה לְהִלָּחֶם בִּי&quot;</p><p>שמואל א כח21: &quot;וַתָּבוֹא הָאִשָּׁה אֶל שָׁאוּל וַתֵּרֶא כִּי נִבְהַל מְאֹד וַתֹּאמֶר אֵלָיו הִנֵּה שָׁמְעָה שִׁפְחָתְךָ בְּקוֹלֶךָ וָאָשִׂים נַפְשִׁי בְּכַפִּי....... וָאֶשְׁמַע אֶת דְּבָרֶיךָ אֲשֶׁר דִּבַּרְתָּ אֵלָי&quot;</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-07 10:13:57'
		)
		;

