		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1002_4.html',
		'<p>********** תורת 360 מעלות לאדם על פי השקפת דיין **********</p><p>העולם הוא עגול אינו מתקדם בקו ישר אלא נע במחזור של 360 מעלות.</p><p>ב־0° היה גן‑עדן: הרמוניה בין אדם, חיה ושדה, ללא גדרות, ללא שליטה וללא אכזריות.</p><p>ב־90° החלה ההתרחקות: האדם התחיל לעבוד את האדמה, לבנות, לגדר, לשלוט ולהרחיק את חיות הבר.</p><p>ב־180° הגענו לשיא ההתרחקות: ערים, כבישים, בטון, גדרות, חיות בר שנעלמות, שדה שנגזל מחיית השדה, עולם שבור.</p><p>אי‑אפשר לחזור אחורה ל־90°; ההיסטוריה אינה חוזרת לאחור.</p><p>המעגל מתקדם קדימה אל 270° — תחילת התיקון: מודעות, חמלה, שמירת טבע, הגנה על חיות בר, החזרת שטחים פתוחים, תיקון מוסרי של יחס האדם לבריאה.</p><p>ב־360° מושלם המעגל: שיבה לגן‑עדן לא כעבר אלא כעתיד מתוקן — עולם שבו האדם חי בהרמוניה עם הטבע, החיות חיות בשדה, אין גזל, אין השחתה, יש צדק, חמלה ושלום בין כל הברואים.</p><p>תורת 360 המעלות מלמדת שהשדה שייך גם לחיית השדה, שהבריאה אינה רכוש, שהחיה אינה מטרד, ושחמלה היא יסוד הבריאה.</p><p>זהו חזון הנביאים: “לא ירעו ולא ישחיתו”, “וגר זאב עם כבש”.</p><p>גן‑עדן אמנם כבר מאחורינו — אך מבחינת המעגל הוא לפנינו בהשלמת המעגל</p><p>-----------------------------------------------------------------------------------------</p><p> “כִּי לֹא יֶחְדַּל אֶבְיוֹן מִקֶּרֶב הָאָרֶץ” — נאמר בזמן שהארץ מקולקלת, כאשר האדם גוזל את השדה והבריאה נאנחת. אך ביום שיוסר העוול מן הארץ, וכאשר לא יהיה עוד עוני סביבתי — לא עוני של אדם בלבד, אלא עוני של שדה, של חיות, של טבע שנגזל — אז גם האביונים יקומו לתחייה. אז יתקיים הכתוב: “וְיָסְפוּ עֲנָוִים בַּיהוָה שִׂמְחָה, וְאֶבְיוֹנֵי אָדָם בִּקְדוֹשׁ יִשְׂרָאֵל יָגִילוּ.” כי כאשר הארץ תשוב להיות ארץ של צדק וחמלה, של שדה הפתוח גם לחיית השדה, אז גם האדם העני ימצא את מקומו ויגיל. תיקון הבריאה ותיקון האדם — כרוכים זה בזה. וכאשר העולם ישוב אל שלמותו, אל 360 המעלות, אל גן‑עדן המתוקן — יהיו אמנם אביונים, אך אלה יהיו ככתוב: “וְאֶבְיוֹנֵי אָדָם בִּקְדוֹשׁ יִשְׂרָאֵל יָגִילוּ.”</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-08 12:53:22'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

