		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/daian.html',
		'<p>חבקוק ב1: &quot;עַל מִשְׁמַרְתִּי אֶעֱמֹדָה וְאֶתְיַצְּבָה עַל מָצוֹר וַאֲצַפֶּה לִרְאוֹת מַה יְדַבֶּר בִּי וּמָה אָשִׁיב עַל תּוֹכַחְתִּי&quot; </p><p>חבקוק ב2: &quot;וַיַּעֲנֵנִי יהוה וַיֹּאמֶר כְּתוֹב חָזוֹן וּבָאֵר עַל הַלֻּחוֹת לְמַעַן יָרוּץ קוֹרֵא בוֹ&quot; </p><p>לאמור בכתיבה לכתוב החזון לבאר ולפרש מפורש ושום שכל כדי שיבינו היטב --- וזה מה שאני כותב</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-09 04:58:51'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

