		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2728_3.html',
		'<p>להיות צמחוני כן או לא</p><p>האמת שזו לא שאלה תזונתית —זו שאלה מוסרית.</p><p>תהלים קיא4-5: &quot;זֵכֶר עָשָׂה לְנִפְלְאֹתָיו חַנּוּן וְרַחוּם יהוה ***טֶרֶף נָתַן לִירֵאָיו*** יִזְכֹּר לְעוֹלָם בְּרִיתוֹ&quot;</p><p>אם אתה ירא-אלהים אתה יכול לאכול בשר זה מותר לך ואם אתה איש עַוָּל אסור לך לאכול בשר</p><p>איוב כט17: &quot;וָאֲשַׁבְּרָה מְתַלְּעוֹת עַוָּל וּמִשִּׁנָּיו אַשְׁלִיךְ טָרֶף&quot;...</p><p>-------------------------------------------------------------------</p><p>צמחונות אינה חובה וגם אכילת בשר אינה חובה</p><p>אכילת בשר אינה זכות אוטומטית</p><p>האדם צריך לבדוק את מדרגתו המוסרית</p><p>רק מי שמתקן את מידותיו — ראוי לקבל “טֶרֶף”</p><p>זה הופך את אכילת הבשר לעניין של אחריות מוסרית, לא של תיאבון.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-09 08:40:53'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
