		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0531_1.html',
		'<p>בפרשת שמיני בספר ויקרא </p><p>משה עשה מבחן לבני אהרן מי ימשיך את שושלת הכהונה</p><p>עתה שימו לב כי........................................................</p><p>הכפרה בצדקה ומשפט חסד ורחמים מכובדת יותר מכפרה בבהמה</p><p>ספר במדבר פרק טז במדבר טז5:</p><p>&quot;וַיְדַבֵּר אֶל קֹרַח וְאֶל כָּל עֲדָתוֹ לֵאמֹר בֹּקֶר וְיֹדַע יהוה אֶת אֲשֶׁר לוֹ</p><p>וְאֶת הַקָּדוֹשׁ וְהִקְרִיב אֵלָיו וְאֵת אֲשֶׁר יִבְחַר בּוֹ יַקְרִיב אֵלָיו&quot;</p><p>***וְאֶת הַקָּדוֹשׁ וְהִקְרִיב אֵלָיו *** וְאֵת אֲשֶׁר יִבְחַר בּוֹ יַקְרִיב אֵלָיו</p><p>******* וְאֶת הַקָּדוֹשׁ וְהִקְרִיב אֵלָיו = בִּקְרֹבַי אֶקָּדֵשׁ = אֲקַדֵּשׁ לְכַהֵן לִי *******</p><p>שמות כט44: &quot;וְקִדַּשְׁתִּי אֶת אֹהֶל מוֹעֵד וְאֶת הַמִּזְבֵּחַ וְאֶת אַהֲרֹן וְאֶת בָּנָיו אֲקַדֵּשׁ לְכַהֵן לִי&quot;</p><p>ואכן אלהים קידש את אהרן ובניו וציוה לכפר עליהם שבעת ימים</p><p>ויקרא ח34: &quot;כַּאֲשֶׁר עָשָׂה בַּיּוֹם הַזֶּה צִוָּה יהוה לַעֲשֹׂת לְכַפֵּר עֲלֵיכֶם&quot;</p><p>ויקרא ח35: &quot;וּפֶתַח אֹהֶל מוֹעֵד תֵּשְׁבוּ יוֹמָם וָלַיְלָה שִׁבְעַת יָמִים וּשְׁמַרְתֶּם אֶת מִשְׁמֶרֶת יהוה וְלֹא תָמוּתוּ כִּי כֵן צֻוֵּיתִי&quot;</p><p>******** אבל ביום השמיני שימו לב כי הכפרה בבהמת הקורבן רק על אהרן והעם ואין כפרת קורבן לבני אהרן ********</p><p>ויקרא ט7:</p><p>&quot;וַיֹּאמֶר מֹשֶׁה אֶל אַהֲרֹן קְרַב אֶל הַמִּזְבֵּחַ וַעֲשֵׂה אֶת חַטָּאתְךָ וְאֶת עֹלָתֶךָ</p><p>וְכַפֵּר בַּעַדְךָ וּבְעַד הָעָם וַעֲשֵׂה אֶת קָרְבַּן הָעָם וְכַפֵּר בַּעֲדָם כַּאֲשֶׁר צִוָּה יהוה\'&quot;</p><p>ביום השמיני לא כיפרו בבהמת קורבן על בני אהרן וזאת כדי לראות מי מדור ההמשך ישרוד את הקודש ללא כפרת קורבן</p><p>והיה אשר ישרוד את הקודש ללא כפרת קורבן בהמה הוא הצדיק כי כפרתו רק בחסד ואמת וביראת אלהים</p><p>משלי טז6: &quot;בְּחֶסֶד וֶאֱמֶת יְכֻפַּר עון וּבְיִרְאַת יהוה סוּר מֵרָע&quot;</p><p>הושע ו6: &quot;כִּי חֶסֶד חָפַצְתִּי וְלֹא זָבַח וְדַעַת אֱלֹהִים מֵעֹלוֹת&quot;</p><p>-----------------------------------------------------------------</p><p>כעת לבאור הפסוק</p><p>ויקרא י3: &quot;וַיֹּאמֶר מֹשֶׁה אֶל אַהֲרֹן הוּא אֲשֶׁר דִּבֶּר יהוה לֵאמֹר - -- בִּקְרֹבַי אֶקָּדֵשׁ וְעַל פְּנֵי כָל הָעָם אֶכָּבֵד וַיִּדֹּם אַהֲרֹן&quot;</p><p>בִּקְרֹבַי אֶקָּדֵשׁ = בקרובים אלי אקדש אותם ככתוב: וְאֶת הַקָּדוֹשׁ וְהִקְרִיב אֵלָיו = בִּקְרֹבַי אֶקָּדֵשׁ = אֲקַדֵּשׁ לְכַהֵן לִי</p><p>וְעַל פְּנֵי כָל הָעָם אֶכָּבֵד = ככתוב: וְאִכָּבְדָה בְּפַרְעֹה וּבְכָל חֵילוֹ בְּרִכְבּוֹ וּבְפָרָשָׁיו = או ככתוב: תִּכְבַּד עָלַי יָדֶךָ נֶהְפַּךְ לְשַׁדִּי בְּחַרְבֹנֵי קַיִץ סֶלָה</p><p>--------------------------</p><p>חשוב לדעת כי בתחילת היום השמיני כבר היה רמז למות שמתקרב וכי יש לדעת להתמודד עמו רק ביראת אלהים</p><p>ורק אלעזר ואיתמר בני אהרן הנותרים זכו לכפרה ולא בבהמה כי בְּחֶסֶד וֶאֱמֶת יְכֻפַּר עון וּבְיִרְאַת יהוה סוּר מֵרָע</p><p>ויקרא ט4: &quot;וְשׁוֹר וָאַיִל לִשְׁלָמִים לִזְבֹּחַ לִפְנֵי יהוה וּמִנְחָה בְּלוּלָה בַשָּׁמֶן כִּי הַיּוֹם יהוה נִרְאָה אֲלֵיכֶם&quot;</p><p>שמות לג20: &quot;וַיֹּאמֶר לֹא תוּכַל לִרְאֹת אֶת פָּנָי כִּי לֹא יִרְאַנִי הָאָדָם וָחָי&quot; =כִּי הַיּוֹם יהוה נִרְאָה אֲלֵיכֶם</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-10 12:30:16'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

