		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2655_4.html',
		'<p>תהלים קג5: &quot;הַמַּשְׂבִּיַע בַּטּוֹב עֶדְיֵךְ תִּתְחַדֵּשׁ כַּנֶּשֶׁר נְעוּרָיְכִי&quot;</p><p>ואם יהוה חידש כַּנֶּשֶׁר נְעוּרָיְכִי אל תשיב רעה תחת טובה</p><p>תהלים קיט9: &quot;בַּמֶּה יְזַכֶּה נַּעַר אֶת אָרְחוֹ לִשְׁמֹר כִּדְבָרֶךָ&quot;</p><p>שמואל ב כב22: &quot;כִּי שָׁמַרְתִּי דַּרְכֵי יהוה וְלֹא רָשַׁעְתִּי מֵאֱלֹהָי&quot;</p><p>תהלים יח22: &quot;כִּי שָׁמַרְתִּי דַּרְכֵי יהוה וְלֹא רָשַׁעְתִּי מֵאֱלֹהָי&quot;</p><p>-</p><p>אם אלהים אותך &quot;ציער&quot; אז &quot;צעיר&quot; יעשה אותך אל תדאג</p><p>רק קווה לאלהים בכל לבך והוא ישיב לך נעוריך כאברהם</p><p>ככתוב בספר בראשית כב19: &quot;וַיָּשָׁב אַבְרָהָם אֶל נְעָרָיו [=אֶל נְעורָיו] </p><p>וַיָּקֻמוּ וַיֵּלְכוּ יַחְדָּו אֶל בְּאֵר שָׁבַע וַיֵּשֶׁב אַבְרָהָם בִּבְאֵר שָׁבַע&quot; </p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-10 13:47:29'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

