		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0518_3.html',
		'<p>פרשת שמיני בספר ויקרא בהקשר ליום השמיני אשר מלים את בני ישראל</p><p>ויקרא יב3: &quot;וּבַיּוֹם הַשְּׁמִינִי יִמּוֹל בְּשַׂר עָרְלָתוֹ&quot; ובהסרת ערלת הילד מצילים אותו מאלהי נכר ככתוב: בַּיּוֹם הַשְּׁמִינִי תִּתְּנוֹ לִי</p><p>בספר ויקרא...</p><p>חשוב לדעת כי בתחילת היום השמיני כבר היה רמז למות שמתקרב וכי יש לדעת להתמודד עמו רק ביראת אלהים</p><p>ורק אלעזר ואיתמר בני אהרן הנותרים זכו לכפרה ולא בבהמה כי בְּחֶסֶד וֶאֱמֶת יְכֻפַּר עון וּבְיִרְאַת יהוה סוּר מֵרָע</p><p>ויקרא ט4: &quot;וְשׁוֹר וָאַיִל לִשְׁלָמִים לִזְבֹּחַ לִפְנֵי יהוה וּמִנְחָה בְּלוּלָה בַשָּׁמֶן כִּי הַיּוֹם יהוה נִרְאָה אֲלֵיכֶם&quot;</p><p>שמות לג20: &quot;וַיֹּאמֶר לֹא תוּכַל לִרְאֹת אֶת פָּנָי כִּי לֹא יִרְאַנִי הָאָדָם וָחָי&quot; = כִּי הַיּוֹם יהוה נִרְאָה אֲלֵיכֶם</p><p>ואם הַיּוֹם יהוה נִרְאָה אֲלֵיכֶם ולֹא יִרְאַנִי הָאָדָם וָחָי --- אז מות מגיע הַיּוֹם ---------------------------</p><p>ביום השמיני לאדם הנולד נראה אליו אלהים אשר פוקד אותו ואם ראה כי ערל הוא... וְנִכְרְתָה הַנֶּפֶשׁ הַהִוא מֵעַמֶּיהָ אֶת בְּרִיתִי הֵפַר</p><p>בראשית יז14: &quot;וְעָרֵל זָכָר אֲשֶׁר לֹא יִמּוֹל אֶת בְּשַׂר עָרְלָתוֹ וְנִכְרְתָה הַנֶּפֶשׁ הַהִוא מֵעַמֶּיהָ אֶת בְּרִיתִי הֵפַר&quot; </p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-10 14:25:39'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t2619_1.html',
		'<p>מי שמבקש אמת — חייב להרחיק את השקר. </p><p>מי שמבקש מצוות — חייב להרחיק את המרעים. </p><p>מי שיהוה שומע את קול בכיו — מגרש את פועלי האוון סביבו.</p><p>תהלים ו9: &quot;סוּרוּ מִמֶּנִּי כָּל פֹּעֲלֵי אָוֶן כִּי שָׁמַע יהוה קוֹל בִּכְיִי&quot;</p><p>תהלים קיט115: &quot;סוּרוּ מִמֶּנִּי מְרֵעִים וְאֶצְּרָה מצות אֱלֹהָי&quot; </p><p>מְרֵעִים = כָּל פֹּעֲלֵי אָוֶן </p><p>כִּי שָׁמַע יהוה קוֹל בִּכְיִי --- וְאֶצְּרָה מצות אֱלֹהָי</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-11 17:23:36'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0310_2.html',
		'<p>ויקרא יז3-4: &quot;אִישׁ אִישׁ מִבֵּית יִשְׂרָאֵל אֲשֶׁר יִשְׁחַט שׁוֹר אוֹ כֶשֶׂב אוֹ עֵז בַּמַּחֲנֶה אוֹ אֲשֶׁר יִשְׁחַט מִחוּץ לַמַּחֲנֶה </p><p>וְאֶל פֶּתַח אֹהֶל מוֹעֵד לֹא הֱבִיאוֹ לְהַקְרִיב קָרְבָּן ליהוה לִפְנֵי מִשְׁכַּן יהוה דָּם יֵחָשֵׁב לָאִישׁ הַהוּא דָּם שָׁפָךְ וְנִכְרַת הָאִישׁ הַהוּא מִקֶּרֶב עַמּוֹ&quot;</p><p>ועתה ישראל אתה האוהב לאכול  בשר הזבח מן הצאן והבקר  אש-פר ואש-כר  </p><p>הן היום אין משכן להביא קורבן בְּשַׂר הַזָּבַח פֶּתַח אֹהֶל מוֹעֵד וכעת אייעץ למען לא יֵחָשֵׁב לָאִישׁ הַהוּא דָּם שָׁפָךְ</p><p>לכן אמליץ לך להתרחץ במים לפני הזבח ואחרי הזבח למען תטהר כי ברחצך במים תבוא עליך רוח אלהים המרחפת על פני המים ועל כן יחשב לך כי הבאת קָרְבָּן ליהוה</p><p> </p><p> </p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-11 17:27:45'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0518_3.html',
