		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>הרבנים מצאו זמן וכוח להטיל כשרות על הפלאפון, אך לא מצאו את הלב לשמור על מצוות שהן יסוד המוסר, כמו שמיטת הארץ ויובל. </p><p>במקום להגן על האדמה שניתנה לאדם לשמירה, הם אפשרו — בשתיקה או בהסכמה — הפיכת שדות לפסי בטון, מרחבים חיים למגרשי אספלט, ובריאה שלמה למוצר שניתן לנצל.</p><p> זה אינו רק כישלון הלכתי; זה כישלון מוסרי עמוק. מי שמקפיד על פרטים טכניים אך מתעלם מן העיקר מגלה לב שאיבד את הרגישות הבסיסית ביותר: </p><p>היכולת לראות את העולם כמשהו שיש לשמור עליו ולא רק לשלוט בו. הארץ לא נהרסה בגלל אויבים, אלא בגלל אדישות. </p><p>בגלל לבבות שהתקשו עד שלא הרגישו עוד את כאב האדמה, את זעקת השדה, את האחריות האנושית הפשוטה שלא לגזול את מה שלא שלך. </p><p>וכאשר הלב נעשה אטום — גם הארץ נעשית טרף קל. כך נראית חברה שמדברת על קדושה אך שוכחת את קדושת החיים עצמם.</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-12 16:08:54'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>וקצף שגיא ואמר לְקַטָּלָה כל חכימי כנען להשמדה ולהובדה עד סופא </p><p>משלי טז14: &quot;חֲמַת מֶלֶךְ מַלְאֲכֵי מָוֶת וְאִישׁ חָכָם יְכַפְּרֶנָּה&quot;  -- היש בכם חָכָם אִם אָיִן</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-12 18:52:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>לא רק שלא כיבדו את המלך כי גם התנשאו עליו לאמור סמכות חכמים אנחנו</p><p>וקצף שגיא ואמר לְקַטָּלָה כל חכימי כנען להשמדה ולהובדה עד סופא</p><p>משלי טז14: &quot;חֲמַת מֶלֶךְ מַלְאֲכֵי מָוֶת וְאִישׁ חָכָם יְכַפְּרֶנָּה&quot;  -- היש בכם חָכָם אִם אָיִן</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-12 19:06:01'
		)
		;

