		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1502_2.html',
		'<p>https://www.hidabroot.org/video/60746</p><p>כג וַיִּשָּׁבַע הַמֶּלֶךְ שְׁלֹמֹה בַּיהוָה לֵאמֹר  כֹּה יַעֲשֶׂה-לִּי אֱלֹהִים וְכֹה יוֹסִיף כִּי בְנַפְשׁוֹ דִּבֶּר אֲדֹנִיָּהוּ אֶת-הַדָּבָר הַזֶּה.  </p><p>כד וְעַתָּה חַי-יְהוָה אֲשֶׁר הֱכִינַנִי וַיּוֹשִׁיבַנִי עַל-כִּסֵּא דָּוִד אָבִי וַאֲשֶׁר עָשָׂה-לִי בַּיִת כַּאֲשֶׁר דִּבֵּר  כִּי הַיּוֹם יוּמַת אֲדֹנִיָּהוּ.  </p><p>כה וַיִּשְׁלַח הַמֶּלֶךְ שְׁלֹמֹה בְּיַד בְּנָיָהוּ בֶן-יְהוֹיָדָע וַיִּפְגַּע-בּוֹ וַיָּמֹת.</p><p>ואם דיין המלך משיח אלהים הוא יפגע באדוניהו של הדור הזה אך לא בחרב אדם כי אם בחרב אלהים</p><p>הושע ו5: &quot;עַל כֵּן חָצַבְתִּי בַּנְּבִיאִים הֲרַגְתִּים בְּאִמְרֵי פִי וּמִשְׁפָּטֶיךָ אוֹר יֵצֵא&quot;</p><p>ישעיהו יא4: &quot;וְשָׁפַט בְּצֶדֶק דַּלִּים וְהוֹכִיחַ בְּמִישׁוֹר לְעַנְוֵי אָרֶץ וְהִכָּה אֶרֶץ בְּשֵׁבֶט פִּיו וּבְרוּחַ שְׂפָתָיו יָמִית רָשָׁע&quot;</p><p>והמלך חפץ להשמידם </p><p>כי לא רק שלא כיבדו את המֶלֶךְ כי גם התנשאו עליו לאמור &quot;סמכות חכמים אנחנו&quot;</p><p> אך המלך לא מתרשם מחוכמתם הרקובה כי ראיתי את המניע שלהם</p><p>וקצף שגיא ואמר לְקַטָּלָה כל חכימי כנען להשמדה ולהובדה עד סופא</p><p>משלי טז14: &quot;חֲמַת מֶלֶךְ מַלְאֲכֵי מָוֶת וְאִישׁ חָכָם יְכַפְּרֶנָּה&quot; -- היש בכם חָכָם אִם אָיִן</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-13 03:26:04'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

