		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t08b24_3.html',
		'<p>מבט וזוית ראיה של דיין</p><p>משלי ג25: &quot;אַל תִּירָא מִפַּחַד פִּתְאֹם וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא&quot;</p><p>וּמִשֹּׁאַת רְשָׁעִים כִּי תָבֹא</p><p>וּמִשֹּׁאַת צדיקים לא תָבֹא כי אין דבר כזה</p><p>לכן כל יום השואה הוא בלוף של רשעים</p><p>הביטו אל כבשן האש בספר דניאל אשר הציל יהוה את אהביו</p><p>תהלים כג4: &quot;גַּם כִּי אֵלֵךְ בְּגֵיא צַלְמָוֶת לֹא אִירָא רָע כִּי אַתָּה עִמָּדִי שִׁבְטְךָ וּמִשְׁעַנְתֶּךָ הֵמָּה יְנַחֲמֻנִי&quot;</p><p>-</p><p>יום השואה מנוצל על ידי ישראל להצגתה בעיני הגוים כיהודי נרדף</p><p>בעוד ממשלות ישראל לדורותיהן החריבו את ישראל משנת 1948</p><p>אשר הייתה ישראל זבת חלב ודבש וכיום אין חי וצומח בערי ישראל</p><p>בתכלס השואה הסתיימה לפני 80 שנה וכבר אין באמת שורדי שואה</p><p>אך זה מנוצל על ידי עמותות כזב לנגן לך על הרגשות ולגזול ממך תרומה</p><p>-</p><p>ובאשר ליום השואה הזה שבספירת העומר הלא ימי קציר ברינה יקצורו</p><p>אבל נכון אין קציר יש רק נדלן ועוד נדלן ואספלט ובטון אז כן זה יום שואה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-14 09:00:25'
		)
		;

