		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t09a18_5.html',
		'<p>בהמשך לתגובתי מיום 2019-08-23 03:32:08 DAIAN SHEM</p><p> מלכים א יז18: &quot;וַתֹּאמֶר אֶל אֵלִיָּהוּ מַה לִּי וָלָךְ אִישׁ הָאֱלֹהִים בָּאתָ אֵלַי לְהַזְכִּיר אֶת עוני וּלְהָמִית אֶת בְּנִי&quot;</p><p>איש האלהים בא לְהַזְכִּיר את עון יִשְׂרָאֵל למען ישראל יחדל מגאותו ותהיה בו ענוה</p><p>וכשתהיה ענוה בישראל אז יְבֻקַּשׁ אֶת עון יִשְׂרָאֵל וְאֵינֶנּוּ  וְאֶת חַטֹּאת יְהוּדָה וְלֹא תִמָּצֶאינָה כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר&quot;</p><p>ואתם רבני ישראל אל תכעסו שאיש אלהים מזכיר עוונכם ותחת [במקום] זאת שפרו מעשיכם ודרכיכם לפני יהוה</p><p>עד אשר יראה איש האלהים כי אין מה לְהַזְכִּיר את עון יִשְׂרָאֵל כי [פשוט] איננו ולא ימצא</p><p>ירמיהו נ20: &quot;בַּיָּמִים הָהֵם וּבָעֵת הַהִיא נְאֻם יהוה יְבֻקַּשׁ אֶת עון יִשְׂרָאֵל וְאֵינֶנּוּ וְאֶת חַטֹּאת יְהוּדָה וְלֹא תִמָּצֶאינָה כִּי אֶסְלַח לַאֲשֶׁר אַשְׁאִיר&quot;</p><p>לאמור כי פעולת השטן גם היא מאת יהוה ולמען מטרה טובה לאמור לחפש את עוונך עד שלא ימצא העוון</p><p>גם אתה איש ישראל וכל אדם על פי המשל הזה</p><p>כי כאשר אתה אדם טוב ותרן וסלחן אז גם הרעים יהיו סביבך ולידך</p><p>רק כאשר אתה כשטן לא ותרן ולא סלחן אז הרעים יהיו אתך במחלוקת וריב ורק הטובים ישארו איתך</p><p>לכן לעתים צריך להיות כשטן כדי לבחון לראות ולהיווכח מי הם הטובים שישארו עמך</p><p></p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-18 18:26:50'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

