		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0516_7.html',
		'<p>פרשת פפושדו</p><p>לפי התורה והמדע --- המצה העשירה היא חמץ כי מיץ ענבים תירוש מכיל מים</p><p>לפי ההלכה ---- המצה העשירה כשל&quot;פ כי על פי ההלכה מי פירות אין מחמיצין</p><p>-</p><p>קמח מצות + מיץ ענבים = זה לא תרכובת כי אם תערובת המכילה מים במיץ הענבים</p><p>סוף דבר</p><p>התורה והמדע שניהם יחדיו צודקים</p><p>המצה העשירה היא אינה באמת כשרה לפסח</p><p>-</p><p>ההלכה מסלפת גם את התורה וגם את המדע</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-19 13:47:14'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

