		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t1404_0.html',
		'<p>בתורת משה איש האלהים בספר דברים פרק יז כתוב:</p><p>ח כִּי יִפָּלֵא מִמְּךָ דָבָר לַמִּשְׁפָּט בֵּין-דָּם לְדָם בֵּין-דִּין לְדִין וּבֵין נֶגַע לָנֶגַע דִּבְרֵי רִיבֹת בִּשְׁעָרֶיךָ  וְקַמְתָּ וְעָלִיתָ אֶל-הַמָּקוֹם אֲשֶׁר יִבְחַר יְהוָה אֱלֹהֶיךָ בּוֹ.  </p><p>ט וּבָאתָ אֶל-הַכֹּהֲנִים הַלְוִיִּם וְאֶל-הַשֹּׁפֵט אֲשֶׁר יִהְיֶה בַּיָּמִים הָהֵם וְדָרַשְׁתָּ וְהִגִּידוּ לְךָ אֵת דְּבַר הַמִּשְׁפָּט.  </p><p>י וְעָשִׂיתָ עַל-פִּי הַדָּבָר אֲשֶׁר יַגִּידוּ לְךָ מִן-הַמָּקוֹם הַהוּא אֲשֶׁר יִבְחַר יְהוָה וְשָׁמַרְתָּ לַעֲשׂוֹת כְּכֹל אֲשֶׁר יוֹרוּךָ.  </p><p>יא עַל-פִּי הַתּוֹרָה אֲשֶׁר יוֹרוּךָ וְעַל-הַמִּשְׁפָּט אֲשֶׁר-יֹאמְרוּ לְךָ תַּעֲשֶׂה  לֹא תָסוּר מִן-הַדָּבָר אֲשֶׁר-יַגִּידוּ לְךָ יָמִין וּשְׂמֹאל.  </p><p>יב וְהָאִישׁ אֲשֶׁר-יַעֲשֶׂה בְזָדוֹן לְבִלְתִּי שְׁמֹעַ אֶל-הַכֹּהֵן הָעֹמֵד לְשָׁרֶת שָׁם אֶת-יְהוָה אֱלֹהֶיךָ אוֹ אֶל-הַשֹּׁפֵט וּמֵת הָאִישׁ הַהוּא וּבִעַרְתָּ הָרָע מִיִּשְׂרָאֵל.  </p><p>יג וְכָל-הָעָם יִשְׁמְעוּ וְיִרָאוּ וְלֹא יְזִידוּן עוֹד.</p><p>-</p><p>עתה השכילו כי השופט וכהני יהוה הם [בבחינת] אלהים</p><p>והרבנים אינם אלהים אלא בבחינת הכהנים ***הַנִּגָּשִׁים*** אֶל יהוה </p><p>לאמור כי לרבנים יש **גישה** אל יהוה אבל הם אינם יהוה ככהן ושופט</p><p>שמות יט22: &quot;וְגַם הַכֹּהֲנִים ***הַנִּגָּשִׁים*** אֶל יהוה יִתְקַדָּשׁוּ פֶּן יִפְרֹץ בָּהֶם יהוה&quot;</p><p>-</p><p>עתה אם כהני הדת הרבנים לא ישמעו בקולו של דיין ככל הדברים אשר כתב לכם דיין ימית אותם </p><p>ולמרות אזהרותי ראיתי כי יש רבנים שממשיכים להתחצף ומאשימים אותי בתאוות ממון וכבוד</p><p>אז אגיד לכם כדברים הבאים....</p><p>כי באשר לממון --- אני כותב באתר הניווט בתנך בהתנדבות מלאה קרוב לעשרים שנה</p><p>ובאשר לכבוד --- ידעתי הכתוב בספר משלי ג35: &quot;כָּבוֹד חֲכָמִים יִנְחָלוּ וּכְסִילִים מֵרִים קָלוֹן&quot; </p><p>לאמור כי אם אתם חכם באמת אז הכבוד יגיע אליך באופן טבעי אוטומט</p><p>ואם לא חכם אתה אז לא יהיה לך כבוד גם אם תשים מצנפת-תרבוש ושמלה עליך</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-23 03:13:04'
		)
		;

SET character_set_client=utf8mb3;
