		INSERT INTO tguvot (parent,body,userid,username,created_at) VALUES (
		'tnk1/messages/prqim_t0231_0.html',
		'<p>מי ששמר שבת כנדרש עשה מטעמים והתענג על יהוה כי קרא לשבת עונג לקדוש יהוה מכובד</p><p>בתם השבת יעשה הבדלה בין הקודש לחול ולא יאכל מטעמים בלילה אין צורך ב&quot;מלוה מלכה&quot;</p><p>כי אם היה לך עונג שבת קודש באופן מלא אז אין-חסר ואם אין-חסר — אין צורך למלא.</p><p>&quot;מלוה מלכה&quot; זאת סעודה מיותרת לא סעודה של שבת-קודש וגם לא בריא לאכול בלילה</p><p>איוב לו20: &quot;אַל תִּשְׁאַף הַלָּיְלָה לַעֲלוֹת עַמִּים תַּחְתָּם&quot;</p><p>אל תעשה מטה-עמים לאכול בלילה מלבד שבתות ומועדי יהוה</p>',
		'115934331744503251746',
		'DAIAN SHEM',
		'2026-04-25 17:27:41'
		)
		;

SET character_set_client=utf8mb3;
SET character_set_connection=utf8mb3;

